window.dataLayer=window.dataLayer||[];function gtag(){dataLayer.push(arguments)}gtag("js",new Date);document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll('a[href*=".html"]').forEach(link=>{link.addEventListener("click",e=>{const destination=link.getAttribute("href");const currentPage=document.body.dataset.page||"home";if(typeof gtag!=="undefined"){gtag("event","page_navigation",{destination_page:destination,source_page:currentPage,link_text:link.textContent.trim()})}})});document.querySelectorAll(".page-nav__pill").forEach(pill=>{pill.addEventListener("click",e=>{const sectionId=pill.getAttribute("href");if(typeof gtag!=="undefined"){gtag("event","section_navigation",{section:sectionId,page:document.body.dataset.page||"home"})}})});document.querySelectorAll('a[target="_blank"], a[href^="http"]').forEach(link=>{if(!link.href.includes("eldorado-plan")&&!link.href.includes("eldoradoks.net")){link.addEventListener("click",e=>{if(typeof gtag!=="undefined"){gtag("event","external_link_click",{link_url:link.href,link_text:link.textContent.trim(),page:document.body.dataset.page||"home"})}})}});document.querySelectorAll('.btn, [role="button"]').forEach(btn=>{btn.addEventListener("click",e=>{if(typeof gtag!=="undefined"){gtag("event","button_click",{button_text:btn.textContent.trim(),button_class:btn.className,page:document.body.dataset.page||"home"})}})});let scrolledAlready={};window.addEventListener("scroll",()=>{const maxScroll=document.documentElement.scrollHeight-window.innerHeight;const scrollPercent=Math.round(window.scrollY/maxScroll*100);const roundedPercent=Math.floor(scrollPercent/25)*25;if(!scrolledAlready[roundedPercent]&&roundedPercent>0){scrolledAlready[roundedPercent]=true;if(typeof gtag!=="undefined"){gtag("event","scroll_depth",{scroll_percent:roundedPercent,page:document.body.dataset.page||"home"})}}},{passive:true})});